// Custom publisher from a callback API
func fetchPublisher(url: URL) -> AnyPublisher<Data, URLError> {
  URLSession.shared.dataTaskPublisher(for: url)
    .map { $0.data }
    .eraseToAnyPublisher()
}

// Compose typed pipeline
fetchPublisher(url: url)
  .decode(type: User.self, decoder: JSONDecoder())
  .mapError { _ in AppError.decoding }
  .receive(on: DispatchQueue.main)
  .sink { _ in } receiveValue: { user in print(user.name) }
  .store(in: &bag)

