// Bridging delegate API into Combine
class LocationBridge: NSObject, CLLocationManagerDelegate {
  let subject = PassthroughSubject<CLLocation, Never>()
  let manager = CLLocationManager()
  override init() {
    super.init(); manager.delegate = self
  }
  func locationManager(_ m: CLLocationManager, didUpdateLocations locs: [CLLocation]) {
    locs.forEach { subject.send($0) }
  }
  var publisher: AnyPublisher<CLLocation, Never> { subject.eraseToAnyPublisher() }
}

