import Combine

// Typeahead pipeline
class SearchVM: ObservableObject {
  @Published var query = ""
  @Published var results: [Result] = []
  private var bag = Set<AnyCancellable>()
  init() {
    $query
      .debounce(for: .milliseconds(300), scheduler: DispatchQueue.main)
      .removeDuplicates()
      .flatMap { q -> AnyPublisher<[Result], Never> in
        if q.isEmpty { return Just([]).eraseToAnyPublisher() }
        return api.searchPublisher(q)
          .replaceError(with: [])
          .eraseToAnyPublisher()
      }
      .receive(on: DispatchQueue.main)
      .assign(to: &$results)
  }
}

