import SwiftUI
import Combine

final class CartVM: ObservableObject {
  @Published private(set) var items: [Item] = []
  @Published var coupon: String = ""
  @Published private(set) var total: Decimal = 0
  private var bag = Set<AnyCancellable>()

  init() {
    $items
      .map { $0.reduce(Decimal.zero) { $0 + $1.price } }
      .combineLatest($coupon.map(discount(for:)))
      .map { subtotal, percent in subtotal * (1 - Decimal(percent) / 100) }
      .receive(on: DispatchQueue.main)
      .assign(to: &$total)
  }
  func add(_ item: Item) { items.append(item) }
}

struct CartView: View {
  @StateObject private var vm = CartVM()
  var body: some View {
    VStack {
      TextField("Coupon", text: $vm.coupon)
      Text("Total: \(vm.total)")
      Button("Add") { vm.add(Item(price: 9.99)) }
    }
  }
}

func discount(for coupon: String) -> Int {
  coupon == "OFF10" ? 10 : 0
}

