// async → Publisher via Future
func fetchUserPublisher(id: String) -> AnyPublisher<User, Error> {
  Future { promise in
    Task {
      do { promise(.success(try await api.fetchUser(id: id))) }
      catch { promise(.failure(error)) }
    }
  }
  .eraseToAnyPublisher()
}

// AsyncStream → AnyPublisher (manual bridge)
func publisher<T>(_ stream: AsyncStream<T>) -> AnyPublisher<T, Never> {
  let subject = PassthroughSubject<T, Never>()
  Task {
    for await v in stream { subject.send(v) }
    subject.send(completion: .finished)
  }
  return subject.eraseToAnyPublisher()
}

// View model mixing both
class HybridVM: ObservableObject {
  @Published var query = ""
  @Published var results: [String] = []
  private var bag = Set<AnyCancellable>()
  init() {
    $query.debounce(for: .milliseconds(300), scheduler: DispatchQueue.main)
      .removeDuplicates()
      .sink { [weak self] q in
        Task { @MainActor in
          self?.results = (try? await api.search(q)) ?? []
        }
      }
      .store(in: &bag)
  }
}

// Forgot to store — pipeline silently dies
func bad() {
  somePublisher.sink { _ in print("never") }       // ⚠️ AnyCancellable discarded
}

// Fix
var bag = Set<AnyCancellable>()
func good() {
  somePublisher.sink { _ in print("ok") }.store(in: &bag)
}

// Strong self → leak
publisher.sink { value in self.handle(value) }       // ⚠️
publisher.sink { [weak self] value in self?.handle(value) } // ✅

// Error tears down — use catch
